      const process = await sql`SELECT COUNT(*) FROM tickets WHERE teknisi_id = ${user.id} AND status = 'diproses'`;
      const newTasks = await sql`SELECT COUNT(*) FROM tickets WHERE teknisi_id = ${user.id} AND status = 'ditugaskan'`;

      return {
